/**
 * @fileoverview Dropdown constants.
 * @module module/Dropdown/constants
 */

import { TRANSITION_COLORS } from '../shared/styleFragments.js';
import { defineParts } from '../shared/definePart.js';

/** CSS class names */
export const CLS = Object.freeze({
    ROOT:      'dropdown',
    TRIGGER:   'dropdown-trigger',
    MENU:      'dropdown-menu',
    ITEM:      'dropdown-item',
    DIVIDER:   'dropdown-divider',
    LABEL:     'dropdown-label',
    ICON:      'dropdown-icon',
    HEADER:    'dropdown-header',
    OPEN:      'is-open',
    DISABLED:  'is-disabled',
    FOCUSED:   'is-focused',
});

export const DEFAULTS = Object.freeze({
    trigger: null,       // selector or element for trigger button
    anchor: 'bottom start',  // bottom start | bottom end | top start | top end
    offset: 4,
    items: [],           // [{ label, icon?, href?, onClick?, disabled?, divider? }]
    closeOnSelect: true,
    closeOnOutside: true,
    minWidth: null,
});

export const PART = defineParts('Dropdown', {
    ROOT        : { class: 'dropdown-root', aliases: ['root'] },
    TRIGGER     : { class: 'dropdown-trigger', aliases: ['trigger', 'button'] },
    MENU        : { class: 'dropdown-menu', aliases: ['menu', 'panel'] },
    ITEM        : { class: 'dropdown-item', aliases: ['item', 'option'] },
    DIVIDER     : { class: 'dropdown-divider', aliases: ['divider', 'separator'] },
    LABEL       : { class: 'dropdown-label', aliases: ['label'], tag: 'span' },
    ICON        : { class: 'dropdown-icon', aliases: ['icon'], tag: 'i' },
    HEADER      : { class: 'dropdown-header', aliases: ['header'] },
});

PART.ROOT.jit     = 'inline-block';
PART.TRIGGER.jit  = 'cursor-pointer';
PART.MENU.jit     = `fixed min-w-[var(--dd-min-width)] bg-[var(--dd-bg)] rounded-[var(--dd-radius)] [border:1px_solid_var(--dd-border)] shadow-[var(--dd-shadow)] py-[var(--dd-menu-py)] opacity-0 [transform:scale(0.95)] [transition:opacity_.15s_ease,transform_.15s_ease] pointer-events-none {is-open}:opacity-100 {is-open}:[transform:scale(1)] {is-open}:pointer-events-auto overflow-hidden`;
PART.ITEM.jit     = `flex items-center gap-[var(--dd-item-gap)] px-[var(--dd-item-px)] py-[var(--dd-item-py)] text-[var(--dd-item-font-size)] fg-[var(--dd-item-text)] cursor-pointer ${TRANSITION_COLORS} hover:bg-[var(--dd-item-hover-bg)] {is-disabled}:opacity-50 {is-disabled}:pointer-events-none [text-decoration:none]`;
PART.DIVIDER.jit  = 'h-[1px] bg-[var(--dd-border)] my-[var(--dd-menu-py)]';
PART.LABEL.jit    = 'flex-1 truncate';
PART.ICON.jit     = 'w-[1rem] h-[1rem] shrink-0 fg-[var(--dd-icon-text)]';
PART.HEADER.jit   = 'px-[var(--dd-item-px)] py-[var(--dd-item-py)] text-[var(--dd-header-size)] font-semibold fg-[var(--dd-header-text)]';