/**
 * @fileoverview Dropdown view — DOM setup & positioning.
 * @module module/Dropdown/view
 */

import razyui from '../../index.js';
import { CLS, PART } from './constants.js';

/**
 * Build dropdown menu DOM.
 */
export function setupDOM(root, config) {
    const el = root[0];
    root.addClass(CLS.ROOT);
    PART.ROOT.apply(root);

    // Trigger
    let triggerEl;
    if (config.trigger) {
        triggerEl = typeof config.trigger === 'string'
            ? el.querySelector(config.trigger)
            : config.trigger;
    }
    if (!triggerEl) {
        // Use first child as trigger
        triggerEl = el.firstElementChild;
    }
    if (triggerEl) {
        triggerEl.classList.add(CLS.TRIGGER);
        triggerEl.setAttribute('aria-haspopup', 'menu');
        triggerEl.setAttribute('aria-expanded', 'false');
        const $trigger = razyui(triggerEl);
        PART.TRIGGER.apply($trigger);
    }

    // Menu container — portaled to document.body for proper stacking
    const menu = document.createElement('div');
    menu.className = CLS.MENU;
    menu.setAttribute('role', 'menu');
    const $menu = razyui(menu);
    $menu.addClass('dropdown');  // token scoping class for --dd-* tokens
    PART.MENU.apply($menu);

    // Inherit data-theme from closest themed ancestor
    const theme = el.closest('[data-theme]')?.getAttribute('data-theme');
    if (theme) menu.setAttribute('data-theme', theme);

    document.body.appendChild(menu);

    // Build items
    const itemEls = [];
    if (config.items?.length) {
        for (const item of config.items) {
            if (item.divider || item.type === 'divider') {
                const $div = PART.DIVIDER.create({ role: 'separator' });
                $menu.append($div);
                continue;
            }

            if (item.header || item.type === 'header') {
                const $hdr = PART.HEADER.create();
                $hdr.text(item.header || item.label || '');
                $menu.append($hdr);
                continue;
            }

            // Dynamic tag: <a> for links, <div> otherwise — use apply()
            const tag = item.href ? 'a' : 'div';
            const $item = razyui.el(tag, { className: CLS.ITEM, role: 'menuitem' });
            PART.ITEM.apply($item);
            if (item.href) $item.attr('href', item.href);
            if (item.disabled) $item.addClass(CLS.DISABLED);

            // Icon
            if (item.icon) {
                const $icon = PART.ICON.create().addClass(item.icon);
                $item.append($icon);
            }

            // Label
            const $label = PART.LABEL.create().text(item.label || '');
            $item.append($label);

            $menu.append($item);

            itemEls.push({ el: $item[0], config: item });
        }
    }

    return { triggerEl, menu, itemEls };
}

/**
 * Remove the portaled menu from the DOM.
 */
export function removeMenu(menu) {
    if (menu && menu.parentNode) {
        menu.parentNode.removeChild(menu);
    }
}
